module top_module (
    input rst_clk,
    input d,
    input reset,
    output reg q
);

    // D flip-flop with asynchronous reset logic
    always @(posedge rst_clk or posedge reset) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

endmodule
